const body = $input.first().json.body ?? $input.first().json;
const { sequence_id, step_id, cascade_mode = 'none', cascade_days = 0, cancel_appointment = false, notify_patient = false } = body;

if (!sequence_id) throw new Error('sequence_id is required');
if (!step_id) throw new Error('step_id is required');

const doCascade = cascade_mode !== 'none' && cascade_days !== 0;

return [{ json: { sequence_id, step_id, cascade_mode, cascade_days: parseInt(cascade_days, 10) || 0, cancel_appointment: !!cancel_appointment, notify_patient: !!notify_patient, doCascade } }];

const rows = $input.all();
if (rows.length === 0) throw new Error('Step not found');

const step = rows[0].json;
const parse = $('Parse Input').first().json;

const hasAppointment = !!step.appointment_id;
const shouldCancelAppt = parse.cancel_appointment && hasAppointment;

// Build cancel appointment SQL
const cancelApptSQL = shouldCancelAppt
  ? `UPDATE appointments SET status = 'cancelled' WHERE id = '${step.appointment_id}';`
  : '';

// Delete step SQL
const deleteSQL = `DELETE FROM treatment_steps WHERE id = '${step.id}';`;

// Renumber: step_number -= 1 for all steps after the deleted one
const renumberSQL = `
  UPDATE treatment_steps
  SET step_number = step_number - 1
  WHERE sequence_id = '${parse.sequence_id}'
    AND step_number > ${step.step_number}
`;

return [{ json: {
  ...parse,
  deletedStepNumber: step.step_number,
  appointment_id: step.appointment_id || null,
  cancelApptSQL,
  deleteSQL,
  renumberSQL,
} }];

// Shift remaining steps' dates by cascade_days (negative = pull forward)
const d = $('Build SQL').first().json;
const { sequence_id, deletedStepNumber, cascade_days } = d;

const stepCascadeSQL = `
  UPDATE treatment_steps
  SET scheduled_date = (scheduled_date::date + INTERVAL '${cascade_days} days')::date
  WHERE sequence_id = '${sequence_id}'
    AND step_number >= ${deletedStepNumber}   -- already renumbered, so >= deleted means 'after'
    AND scheduled_date IS NOT NULL
`;

const apptCascadeSQL = `
  UPDATE appointments
  SET
    start_datetime = start_datetime + INTERVAL '${cascade_days} days',
    end_datetime   = end_datetime   + INTERVAL '${cascade_days} days'
  WHERE sequence_id = '${sequence_id}'
    AND step_position >= ${deletedStepNumber}
    AND status NOT IN ('cancelled', 'completed')
`;

return [{ json: { sequence_id, stepCascadeSQL, apptCascadeSQL } }];

// Merge from either cascade or skip path and set sequence_id for fetch
const parse = $('Parse Input').first().json;
return [{ json: { sequence_id: parse.sequence_id } }];

const steps = $input.all().map(r => ({
  id: r.json.id,
  sequence_id: r.json.sequence_id,
  step_number: r.json.step_number,
  step_name: r.json.step_name,
  scheduled_date: r.json.scheduled_date || null,
  duration_minutes: r.json.duration_minutes,
  status: r.json.status,
  notes: r.json.notes || null,
  appointment_id: r.json.appointment_id || null,
  completed_at: r.json.completed_at || null,
}));
return [{ json: { success: true, affected_steps: steps } }];
